import React, { useState } from 'react';
import { User, Lock, GraduationCap, Calculator } from 'lucide-react';

const LoginScreen = ({ onLogin }) => {
  const [selectedRole, setSelectedRole] = useState('');

  const handleRoleSelect = (role) => {
    setSelectedRole(role);
  };

  const handleLogin = () => {
    if (selectedRole) {
      onLogin(selectedRole);
    }
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-primary-50 to-primary-100 flex items-center justify-center p-4">
      <div className="bg-white rounded-2xl shadow-xl p-8 w-full max-w-md">
        <div className="text-center mb-8">
          <div className="inline-flex items-center justify-center w-16 h-16 bg-primary-600 rounded-full mb-4">
            <GraduationCap className="w-8 h-8 text-white" />
          </div>
          <h1 className="text-2xl font-bold text-gray-900 mb-2">HCE-FMS</h1>
          <p className="text-gray-600">Hệ thống Quản lý tài chính - học phí tích hợp AI</p>
        </div>

        <div className="space-y-4 mb-6">
          <label className="block text-sm font-medium text-gray-700 mb-2">
            Chọn vai trò đăng nhập:
          </label>

          <button
            onClick={() => handleRoleSelect('STUDENT')}
            className={`w-full p-4 rounded-lg border-2 transition-all duration-200 ${
              selectedRole === 'STUDENT'
                ? 'border-primary-500 bg-primary-50'
                : 'border-gray-200 hover:border-gray-300'
            }`}
          >
            <div className="flex items-center justify-center space-x-3">
              <User className="w-5 h-5 text-primary-600" />
              <span className="font-medium">Sinh viên</span>
            </div>
          </button>

          <button
            onClick={() => handleRoleSelect('ACCOUNTANT')}
            className={`w-full p-4 rounded-lg border-2 transition-all duration-200 ${
              selectedRole === 'ACCOUNTANT'
                ? 'border-primary-500 bg-primary-50'
                : 'border-gray-200 hover:border-gray-300'
            }`}
          >
            <div className="flex items-center justify-center space-x-3">
              <Calculator className="w-5 h-5 text-primary-600" />
              <span className="font-medium">Kế toán / Admin</span>
            </div>
          </button>
        </div>

        <button
          onClick={handleLogin}
          disabled={!selectedRole}
          className={`w-full py-3 px-4 rounded-lg font-medium transition-all duration-200 ${
            selectedRole
              ? 'bg-primary-600 hover:bg-primary-700 text-white'
              : 'bg-gray-200 text-gray-400 cursor-not-allowed'
          }`}
        >
          Đăng nhập
        </button>

        <div className="mt-6 text-center text-sm text-gray-500">
          Demo: Chọn vai trò và nhấn đăng nhập để tiếp tục
        </div>
      </div>
    </div>
  );
};

export default LoginScreen;
